import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

function Home() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-blue-600 mb-4">
          📚 Study Group Finder
        </h1>
        <p className="text-gray-600 mb-6">Welcome to the app!</p>
        <a 
          href="/login" 
          className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          Go to Login
        </a>
      </div>
    </div>
  );
}

function Login() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="bg-white p-8 rounded-lg shadow-md w-96">
        <h2 className="text-2xl font-bold mb-6 text-center">Login</h2>
        <input 
          type="email" 
          placeholder="Email" 
          className="w-full px-3 py-2 border rounded mb-3"
        />
        <input 
          type="password" 
          placeholder="Password" 
          className="w-full px-3 py-2 border rounded mb-4"
        />
        <button className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700">
          Sign In
        </button>
        <p className="text-center mt-4">
          <a href="/register" className="text-blue-600">Create account</a>
        </p>
      </div>
    </div>
  );
}

function Register() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="bg-white p-8 rounded-lg shadow-md w-96">
        <h2 className="text-2xl font-bold mb-6 text-center">Register</h2>
        <input placeholder="Full Name" className="w-full px-3 py-2 border rounded mb-3" />
        <input type="email" placeholder="Email" className="w-full px-3 py-2 border rounded mb-3" />
        <input type="password" placeholder="Password" className="w-full px-3 py-2 border rounded mb-4" />
        <button className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700">
          Register
        </button>
        <p className="text-center mt-4">
          <a href="/login" className="text-blue-600">Back to Login</a>
        </p>
      </div>
    </div>
  );
}

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
      </Routes>
    </Router>
  );
}

export default App;
